import itertools


class Solution:
    def maximumScore(self, grid):
        n = len(grid)
        best = 0
        for combo in itertools.product(range(n + 1), repeat=n):
            score = 0
            for j in range(n):
                hleft = combo[j - 1] if j > 0 else 0
                hright = combo[j + 1] if j < n - 1 else 0
                m = max(hleft, hright)
                for i in range(combo[j], m):
                    score += grid[i][j]
            if score > best:
                best = score
        return best

