class Solution:
    def maximumScore(self, grid):
        n = len(grid)
        if n == 1:
            return 0
        colpre = [[0] * (n + 1) for _ in range(n)]
        for j in range(n):
            for i in range(n):
                colpre[j][i + 1] = colpre[j][i] + grid[i][j]

        def colsum(j, lo, hi):
            if hi <= lo:
                return 0
            return colpre[j][hi] - colpre[j][lo]

        NEG = float('-inf')
        dp = [[NEG] * (n + 1) for _ in range(n + 1)]
        for h0 in range(n + 1):
            dp[0][h0] = 0

        for j in range(n - 1):
            newdp = [[NEG] * (n + 1) for _ in range(n + 1)]
            for hcur in range(n + 1):
                PM = [NEG] * (n + 2)
                best = NEG
                for hp in range(n + 1):
                    v = dp[hp][hcur]
                    if v > best:
                        best = v
                    PM[hp] = best
                G = [NEG] * (n + 1)
                for hp in range(n + 1):
                    v = dp[hp][hcur]
                    if v == NEG:
                        continue
                    G[hp] = v + colsum(j, hcur, hp)
                SM = [NEG] * (n + 2)
                best2 = NEG
                for hp in range(n, -1, -1):
                    if G[hp] > best2:
                        best2 = G[hp]
                    SM[hp] = best2
                for hnext in range(n + 1):
                    opt1 = NEG
                    if PM[hnext] != NEG:
                        opt1 = colsum(j, hcur, hnext) + PM[hnext]
                    opt2 = SM[hnext + 1] if hnext + 1 <= n else NEG
                    val = max(opt1, opt2)
                    if val > newdp[hcur][hnext]:
                        newdp[hcur][hnext] = val
            dp = newdp

        ans = NEG
        last_j = n - 1
        for hprev in range(n + 1):
            for hlast in range(n + 1):
                if dp[hprev][hlast] == NEG:
                    continue
                val = dp[hprev][hlast] + colsum(last_j, hlast, hprev)
                if val > ans:
                    ans = val
        return ans

