var maximumScore = function(grid) {
    const n = grid.length;
    if (n === 1) return 0;
    const colpre = Array.from({ length: n }, () => new Array(n + 1).fill(0));
    for (let j = 0; j < n; j++) {
        for (let i = 0; i < n; i++) {
            colpre[j][i + 1] = colpre[j][i] + grid[i][j];
        }
    }
    function colsum(j, lo, hi) {
        if (hi <= lo) return 0;
        return colpre[j][hi] - colpre[j][lo];
    }
    const NEG = -Infinity;
    let dp = [];
    for (let hp = 0; hp <= n; hp++) dp.push(new Array(n + 1).fill(NEG));
    for (let h0 = 0; h0 <= n; h0++) dp[0][h0] = 0;

    for (let j = 0; j < n - 1; j++) {
        const newdp = [];
        for (let hp = 0; hp <= n; hp++) newdp.push(new Array(n + 1).fill(NEG));
        for (let hcur = 0; hcur <= n; hcur++) {
            const PM = new Array(n + 2).fill(NEG);
            let best = NEG;
            for (let hp = 0; hp <= n; hp++) {
                const v = dp[hp][hcur];
                if (v > best) best = v;
                PM[hp] = best;
            }
            const G = new Array(n + 1).fill(NEG);
            for (let hp = 0; hp <= n; hp++) {
                const v = dp[hp][hcur];
                if (v === NEG) continue;
                G[hp] = v + colsum(j, hcur, hp);
            }
            const SM = new Array(n + 2).fill(NEG);
            let best2 = NEG;
            for (let hp = n; hp >= 0; hp--) {
                if (G[hp] > best2) best2 = G[hp];
                SM[hp] = best2;
            }
            for (let hnext = 0; hnext <= n; hnext++) {
                let opt1 = NEG;
                if (PM[hnext] !== NEG) opt1 = colsum(j, hcur, hnext) + PM[hnext];
                const opt2 = hnext + 1 <= n ? SM[hnext + 1] : NEG;
                const val = Math.max(opt1, opt2);
                if (val > newdp[hcur][hnext]) newdp[hcur][hnext] = val;
            }
        }
        dp = newdp;
    }

    let ans = NEG;
    const lastJ = n - 1;
    for (let hprev = 0; hprev <= n; hprev++) {
        for (let hlast = 0; hlast <= n; hlast++) {
            if (dp[hprev][hlast] === NEG) continue;
            const val = dp[hprev][hlast] + colsum(lastJ, hlast, hprev);
            if (val > ans) ans = val;
        }
    }
    return ans;
};
